patch:
--- a/priority_encoder.v
+++ b/priority_encoder.v
@@ -7,7 +7,7 @@
   output reg [3:0] priority
 );

-  always @(data_in)
+  always @(*)
   begin
     priority = 4'b0;
     if (data_in[15]) priority = 4'hF;

before_code:
module priority_encoder_16bit (
  input [15:0] data_in,
  input enable,
  output reg [3:0] priority
);

  always @(data_in)
  begin
    priority = 4'b0;
    if (data_in[15]) priority = 4'hF;
    else if (data_in[14]) priority = 4'hE;
    else if (data_in[13]) priority = 4'hD;
    else if (data_in[12]) priority = 4'hC;
    else if (data_in[11]) priority = 4'hB;
    else if (data_in[10]) priority = 4'hA;
    else if (data_in[9]) priority = 4'h9;
    else if (data_in[8]) priority = 4'h8;
    else priority = 4'h0;
  end

endmodule

after_code:
module priority_encoder_16bit (
  input [15:0] data_in,
  input enable,
  output reg [3:0] priority
);

  always @(*)
  begin
    priority = 4'b0;
    if (data_in[15]) priority = 4'hF;
    else if (data_in[14]) priority = 4'hE;
    else if (data_in[13]) priority = 4'hD;
    else if (data_in[12]) priority = 4'hC;
    else if (data_in[11]) priority = 4'hB;
    else if (data_in[10]) priority = 4'hA;
    else if (data_in[9]) priority = 4'h9;
    else if (data_in[8]) priority = 4'h8;
    else priority = 4'h0;
  end

endmodule
